  annotations.rois[roi.id] = ann;
  if(annotations.virtualRois[roi.id]) stampAnnotation(Object.assign(annotations.virtualRois[roi.id], {deleted: ann.deleted}));
  recordAction(ann.deleted ? 'roi_hide' : 'roi_restore');
